//! MediaDevices compatibility bridge.

pub(super) const SOURCE: &str = "function __mediaOk(v){let o={};o.then=function(cb){if(cb){cb(v);}return o;};o.catch=function(){return o;};return o;}function __mediaErr(n,m){let o={};let e={name:n,message:m};o.then=function(){return o;};o.catch=function(cb){if(cb){cb(e);}return o;};return o;}function __mediaLabel(n,l){if(__states[n]=='granted'){return l;}return '';}function __mediaDevice(id,k,l){return {deviceId:id,kind:k,label:l,groupId:'agent-media'};}let __gum=nav.mediaDevices.getUserMedia;nav.mediaDevices={getUserMedia:__gum,enumerateDevices:function(){return __mediaOk([__mediaDevice('camera-1','videoinput',__mediaLabel('camera','Agent Camera')),__mediaDevice('microphone-1','audioinput',__mediaLabel('microphone','Agent Microphone'))]);},getDisplayMedia:function(){return __mediaErr('NotAllowedError','display-capture unsupported');}};";
